-- ============================================================
-- Migration 00040 : Child Directory — Annuaire joueurs Notion (678 joueurs)
-- Table légère sans FK auth.users — import direct depuis Notion
-- Généré le 2026-03-08
-- ============================================================

-- Table child_directory (idempotente)
CREATE TABLE IF NOT EXISTS child_directory (
  id                UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  tenant_id         UUID        NOT NULL REFERENCES tenants(id),

  -- Identité
  display_name      TEXT        NOT NULL,
  birth_date        DATE,
  statut            TEXT,        -- Académicien | Ancien | Nouveau | Stagiaire

  -- Club
  current_club      TEXT,
  niveau_club       TEXT,        -- Elite 1 | Elite 2 | Inter | InterElite 2 | InterProvinciaux | Provinciaux | Régionaux | Semi-Provinciaux

  -- Adresse
  adresse_rue       TEXT,
  code_postal       TEXT,
  localite          TEXT,

  -- Parent 1 (Papa)
  parent1_nom       TEXT,
  parent1_tel       TEXT,
  parent1_email     TEXT,

  -- Parent 2 (Maman)
  parent2_nom       TEXT,
  parent2_tel       TEXT,
  parent2_email     TEXT,

  -- Statuts
  actif             BOOLEAN     NOT NULL DEFAULT true,
  notes_internes    TEXT,

  -- Notion sync
  notion_page_id    TEXT        UNIQUE,
  notion_synced_at  TIMESTAMPTZ,

  -- Soft-delete + timestamps
  deleted_at        TIMESTAMPTZ,
  created_at        TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at        TIMESTAMPTZ NOT NULL DEFAULT now()
);

DO $rls$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename = 'child_directory' AND policyname = 'tenant_isolation') THEN
    ALTER TABLE child_directory ENABLE ROW LEVEL SECURITY;
    CREATE POLICY "tenant_isolation" ON child_directory FOR ALL USING (tenant_id = current_tenant_id());
  END IF;
END $rls$;

CREATE OR REPLACE FUNCTION set_child_directory_updated_at()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN NEW.updated_at = now(); RETURN NEW; END; $$;

DROP TRIGGER IF EXISTS child_directory_updated_at ON child_directory;
CREATE TRIGGER child_directory_updated_at BEFORE UPDATE ON child_directory FOR EACH ROW EXECUTE FUNCTION set_child_directory_updated_at();

CREATE INDEX IF NOT EXISTS idx_child_directory_tenant ON child_directory(tenant_id) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_child_directory_name ON child_directory(tenant_id, display_name) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_child_directory_club ON child_directory(tenant_id, current_club) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_child_directory_notion ON child_directory(notion_page_id) WHERE notion_page_id IS NOT NULL;

-- ============================================================
-- Import joueurs depuis Notion
-- ============================================================
DO $$
DECLARE
  v_tenant_id UUID;
BEGIN
  SELECT id INTO v_tenant_id FROM tenants ORDER BY created_at LIMIT 1;
  IF v_tenant_id IS NULL THEN RAISE EXCEPTION 'Aucun tenant trouvé.'; END IF;
  RAISE NOTICE 'Import vers tenant: %', v_tenant_id;


  RAISE NOTICE '678 joueurs importés.';
END $$;
